/**
 * MedX skiplink accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Skip-to-content links for dashboard pages.
 */
const SKIPLINK_TOKENS = Object.freeze({
  primary: { value: "a11y-skiplink-primary", scope: "a11y" },
  secondary: { value: "a11y-skiplink-secondary", scope: "a11y" },
  muted: { value: "a11y-skiplink-muted", scope: "a11y" },
  accent: { value: "a11y-skiplink-accent", scope: "a11y" },
  surface: { value: "a11y-skiplink-surface", scope: "a11y" },
});

const SKIPLINK_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SKIPLINK_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const skiplinkRegistry = new Map();
const SKIPLINK_listeners = new Set();
let SKIPLINK_seq = 0;

function createSkiplinkId(prefix = "medx-a11y-skiplink") {
  SKIPLINK_seq += 1;
  return `${prefix}-${SKIPLINK_seq}`;
}

function registerSkiplink(config = {}) {
  const entryId = config.id ?? createSkiplinkId();
  const preset = SKIPLINK_PRESETS[config.preset ?? "default"] ?? SKIPLINK_PRESETS.default;
  const token = SKIPLINK_TOKENS[config.token ?? preset.token] ?? SKIPLINK_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SKIPLINK_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  skiplinkRegistry.set(entryId, entry);
  notifySkiplinkListeners("register", entry);
  return entry;
}

function updateSkiplink(id, patch = {}) {
  const entry = skiplinkRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifySkiplinkListeners("update", entry);
  return entry;
}

function resolveSkiplink(id) {
  const entry = skiplinkRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listSkiplinkEntries(filter = {}) {
  let items = Array.from(skiplinkRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onSkiplinkEvent(listener) {
  SKIPLINK_listeners.add(listener);
  return () => SKIPLINK_listeners.delete(listener);
}

function notifySkiplinkListeners(type, entry) {
  for (const listener of SKIPLINK_listeners) {
    try {
      listener({ type, entry, registrySize: skiplinkRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:skiplink] listener error", err.message);
    }
  }
}

function getSkiplinkMetrics() {
  const items = listSkiplinkEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SKIPLINK_TOKENS).length,
    presets: Object.keys(SKIPLINK_PRESETS).length,
  };
}

async function runMedxSkiplink() {
  console.log("[medx:ui:a11y:skiplink] runtime initialized");
  console.log(`[medx:ui:a11y:skiplink] tokens=${Object.keys(SKIPLINK_TOKENS).length} presets=${Object.keys(SKIPLINK_PRESETS).length}`);

  const events = [];
  onSkiplinkEvent((e) => events.push(e.type));

  const domains = Object.keys(SKIPLINK_SUPPLY_CHAIN);
  const presets = Object.keys(SKIPLINK_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerSkiplink({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/skiplink" },
    });
  }

  const first = listSkiplinkEntries()[0];
  if (first) updateSkiplink(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getSkiplinkMetrics();
  const resolved = first ? resolveSkiplink(first.id) : null;

  console.log(`[medx:ui:a11y:skiplink] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:skiplink] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:skiplink] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:skiplink] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:skiplink] bootstrap complete");
}

module.exports = runMedxSkiplink;
